content.content:
body { font-family: system-ui, sans-serif; margin: 40px; }
.layout { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; max-width: 960px; }
.card { padding: 16px; border: 1px solid #ddd; border-radius: 12px; }
.lista { list-style: none; padding: 0; margin: 0; }
.lista li { padding: 10px 12px; border: 1px solid #eee; border-radius: 10px; margin-bottom: 8px; cursor: pointer; }
.lista li.ativo { border-color: #999; }
.muted { color: #666; }
.row { display: flex; gap: 10px; margin-top: 12px; }
input { padding: 10px 12px; border: 1px solid #ddd; border-radius: 10px; width: 100%; box-sizing: border-box; }
button { padding: 10px 12px; cursor: pointer; }

'use strict';

// ============================
// Estado
// ============================
let tarefas = [
  { id: 1, titulo: 'Estudar JS', done: false, prioridade: 2 },
  { id: 2, titulo: 'Exercícios', done: true, prioridade: 1 },
  { id: 3, titulo: 'Projeto', done: false, prioridade: 3 },
];

let selectedId = null;
let nextId = 4;

let draft = { titulo: '', prioridade: 1 };

// ============================
// DOM
// ============================
function assertEl(sel) {
  const el = document.querySelector(sel);
  if (el === null) console.error(`[tarefas] elemento não encontrado: ${sel}`);
  return el;
}

const elLista = assertEl('#lista');
const btnNova = assertEl('#nova');
const elStatus = assertEl('#status');
const elTitulo = assertEl('#titulo');
const elPrio = assertEl('#prio');
const btnSalvar = assertEl('#salvar');
const btnRemover = assertEl('#remover');
const btnAlternar = assertEl('#alternar');

const hasDom = Boolean(elLista && btnNova && elStatus && elTitulo && elPrio && btnSalvar && btnRemover && btnAlternar);

// ============================
// Utilitários
// ============================
function findById(lista, id) {
  return lista.find((t) => t.id === id) || null;
}

function toIntClamped(raw, min, max) {
  const n = Number(raw);
  if (Number.isNaN(n)) return min;
  return Math.max(min, Math.min(max, Math.trunc(n)));
}

// ============================
// Render
// ============================
function renderLista() {
  elLista.innerHTML = '';

  for (const t of tarefas) {
    const li = document.createElement('li');
    li.textContent = `${t.done ? '✅' : '⬜'} [${t.prioridade}] ${t.titulo}`;
    if (t.id === selectedId) li.classList.add('ativo');
    li.addEventListener('click', () => selectById(t.id));
    elLista.appendChild(li);
  }
}

function renderDetalhes() {
  if (selectedId === null) {
    elStatus.textContent = 'Nenhuma selecionada';
    elTitulo.value = '';
    elPrio.value = '';
    elTitulo.disabled = true;
    elPrio.disabled = true;
    return;
  }

  elTitulo.disabled = false;
  elPrio.disabled = false;

  elTitulo.value = draft.titulo;
  elPrio.value = String(draft.prioridade);

  const t = findById(tarefas, selectedId);
  elStatus.textContent = t ? `Selecionada: #${t.id}` : 'Selecionada: (não encontrada)';
}

function render() {
  if (!hasDom) return;
  renderLista();
  renderDetalhes();
}

// ============================
// Ações (imutáveis)
// ============================
function selectById(id) {
  selectedId = id;
  const t = findById(tarefas, id);
  draft = t ? { titulo: t.titulo, prioridade: t.prioridade } : { titulo: '', prioridade: 1 };
  render();
}

function atualizarDraft() {
  draft = {
    titulo: String(elTitulo.value).trim(),
    prioridade: toIntClamped(elPrio.value, 1, 3),
  };
}

function salvar() {
  if (selectedId === null) return;
  atualizarDraft();

  if (draft.titulo.length === 0) {
    console.warn('[tarefas] título vazio');
    renderDetalhes();
    return;
  }

  tarefas = tarefas.map((t) => {
    if (t.id !== selectedId) return t;
    return { ...t, titulo: draft.titulo, prioridade: draft.prioridade };
  });

  render();
}

function alternarFeito() {
  if (selectedId === null) return;

  tarefas = tarefas.map((t) => {
    if (t.id !== selectedId) return t;
    return { ...t, done: !t.done };
  });

  render();
}

function remover() {
  if (selectedId === null) return;

  tarefas = tarefas.filter((t) => t.id !== selectedId);
  selectedId = null;
  draft = { titulo: '', prioridade: 1 };
  render();
}

function novaTarefa() {
  const t = { id: nextId++, titulo: 'Nova tarefa', done: false, prioridade: 2 };
  tarefas = [...tarefas, t];
  selectById(t.id);
}

// ============================
// Eventos
// ============================
function wire() {
  if (!hasDom) return;

  btnNova.addEventListener('click', novaTarefa);
  btnSalvar.addEventListener('click', salvar);
  btnRemover.addEventListener('click', remover);
  btnAlternar.addEventListener('click', alternarFeito);

  elTitulo.addEventListener('input', () => { atualizarDraft(); renderDetalhes(); });
  elPrio.addEventListener('input', () => { atualizarDraft(); renderDetalhes(); });
}

wire();
render();
console.log('[tarefas] pronto');
